#include <stdio.h>
#include <stdlib.h>
#include <limits.h>
#define MAX_N 200000
#define MAX_Q 200000
#define INF INT_MAX

int abs(int x) { return x < 0 ? -x : x; }

int bfs(int *x, int *y, int n, int s, int f, int c) {
    int *dist = (int *)malloc(n * sizeof(int));
    for (int i = 0; i < n; i++) {
        dist[i] = INF;
    }
    dist[s] = 0;
    int *queue = (int *)malloc(n * sizeof(int));
    int front = 0, rear = 0;
    queue[rear++] = s;
    while (front < rear) {
        int u = queue[front++];
        for (int v = 0; v < n; v++) {
            if (dist[v] == INF && abs(x[u] - x[v]) + abs(y[u] - y[v]) <= c) {
                dist[v] = dist[u] + 1;
                queue[rear++] = v;
            }
        }
    }
    int result = dist[f] != INF;
    free(dist);
    free(queue);
    return result;
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n;
        scanf("%d", &n);
        int *x = (int *)malloc(n * sizeof(int));
        int *y = (int *)malloc(n * sizeof(int));
        for (int i = 0; i < n; i++) {
            scanf("%d %d", &x[i], &y[i]);
        }
        int q;
        scanf("%d", &q);
        while (q--) {
            int s, f;
            scanf("%d %d", &s, &f);
            s--;
            f--;
            int low = 0, high = 1000000000;
            while (low < high) {
                int mid = (low + high) / 2;
                if (bfs(x, y, n, s, f, mid)) {
                    high = mid;
                } else {
                    low = mid + 1;
                }
            }
            printf("%d\n", low);
        }
        free(x);
        free(y);
    }
    return 0;
}

