import java.util.Queue;
import java.util.LinkedList;
import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int t = sc.nextInt();
        while (t-- > 0) {
            int n = sc.nextInt();
            int[] x = new int[n];
            int[] y = new int[n];
            for (int i = 0; i < n; i++) {
                x[i] = sc.nextInt();
                y[i] = sc.nextInt();
            }
            int q = sc.nextInt();
            while (q-- > 0) {
                int s = sc.nextInt() - 1;
                int f = sc.nextInt() - 1;
                int low = 0, high = 1000000000;
                while (low < high) {
                    int mid = (low + high) / 2;
                    if (bfs(x, y, n, s, f, mid)) {
                        high = mid;
                    } else {
                        low = mid + 1;
                    }
                }
                System.out.println(low);
            }
        }
    }

    public static boolean bfs(int[] x, int[] y, int n, int s, int f, int c) {
        int[] dist = new int[n];
        for (int i = 0; i < n; i++) {
            dist[i] = Integer.MAX_VALUE;
        }
        dist[s] = 0;
        Queue<Integer> q = new LinkedList<>();
        q.add(s);
        while (!q.isEmpty()) {
            int u = q.poll();
            for (int v = 0; v < n; v++) {
                if (dist[v] == Integer.MAX_VALUE && Math.abs(x[u] - x[v]) + Math.abs(y[u] - y[v]) <= c) {
                    dist[v] = dist[u] + 1;
                    q.add(v);
                }
            }
        }
        return dist[f] != Integer.MAX_VALUE;
    }
}

